int VFS::addNode(int id, std::string name, std::string type, std::string size, std::string date, std::string content, int parent_id) {
    FileNode node;
    node.id = id;
    node.name = name;
    node.type = type;
    node.size = size;
    node.date = date;
    node.content = content;
    node.parent_id = parent_id;

    nodes.push_back(node);

    if (parent_id != -1) {
        for (auto& p : nodes) {
            if (p.id == parent_id && p.type == "dir") {
                p.children_ids.push_back(node.id);
                break;
            }
        }
    }
    return node.id;
}

const FileNode* VFS::getNode(int id) const {
    for (const auto& node : nodes) {
        if (node.id == id) return &node;
    }
    return nullptr;
}

std::vector<int> VFS::getDirectoryContents(int dir_id) const {
    const FileNode* dir = getNode(dir_id);
    if (dir && dir->type == "dir") {
        return dir->children_ids;
    }
    return {};
}
